import React, { Component } from 'react';
import Container from '../Container';
import './style.css';

export default class CountersPage extends Component {
  state = {
    counter: 0,
  };

  handleDecrease = () => {
    this.setState((prevState) => ({
      counter: prevState.counter - 1,
    }));
  };

  handleIncrease = () => {
    this.setState((prevState) => ({
      counter: prevState.counter + 1,
    }));
  };

  handleReset = () => {
    this.setState({
      counter: 0,
    });
  };

  render() {
    return (
      <Container>
        <main className="counters-page">
          <section className="counter-panel">
            <p className="counter-kicker">Interactive Counter</p>
            <h1>Counters Page</h1>
            <p className="counter-description">
              Practice state updates with a cleaner layout and more polished controls.
            </p>

            <div className="counter-display">
              <span>{this.state.counter}</span>
            </div>

            <div className="counter-actions">
              <button onClick={this.handleDecrease} className="counter-button secondary">
                Decrease
              </button>
              <button onClick={this.handleIncrease} className="counter-button primary">
                Increase
              </button>
            </div>

            <div className="counter-reset-row">
              <button onClick={this.handleReset} className="counter-button neutral">
                Reset
              </button>
            </div>
          </section>
        </main>
      </Container>
    );
  }
}
